## Section1(not reported)
## Problem1(2.8.6.3)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "contextFiniteSolutionSets.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
$x = RandomVariableName(type=>'variable');
$m = random(2,9,1);
$b = non_zero_random(-9,9,1);
$c = random(2,9,1);
Context()->variables->are($x=>'Real');
$linear = Formula("$m $x + $b")->reduce;
$left = Formula("($linear)^2");
$right = Formula("$c^2");
Context("Fraction");
$solnum1 = $c-$b;
$solnum2 = -$c-$b;
$sol1 = Fraction($solnum1,$m);
$sol2 = Fraction($solnum2,$m);
Context("FiniteSolutionSets");
Context()->variables->are($x=>'Real');
$answer = Formula("{$sol1, $sol2}");

############################################################
# Body
############################################################

BEGIN_PGML
Use a square root to solve [`[$left]=[$right]\text{.}`]

[_]{$answer}{25}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
Using the square root property:

[```\newcommand{\amp}{&}
\begin{aligned}
[$linear]\amp=\sqrt{[$right]}\amp\amp\text{or}\amp [$linear]\amp=-\sqrt{[$right]}\\
[$linear]\amp=[$c]\amp\amp\text{or}\amp [$linear]\amp=-[$c]\\
[$m][$x]\amp=[$solnum1]\amp\amp\text{or}\amp [$m][$x]\amp=[$solnum2]\\
[$x]\amp=[$sol1]\amp\amp\text{or}\amp [$x]\amp=[$sol2]
\end{aligned}
```]

So the solution set is [`[$answer]\text{.}`]

END_PGML_SOLUTION

############################################################
# End Problem
############################################################

ENDDOCUMENT();
